#include "./main.h"
#include <math.h>
#include <omp.h>

void kernel_gpu_opencl(
    params_common d_common,
    fp* d_frame,
    int d_frame_no,
    int* d_endoRow,
    int* d_endoCol,
    int* d_tEndoRowLoc,
    int* d_tEndoColLoc,
    int* d_epiRow,
    int* d_epiCol,
    int* d_tEpiRowLoc,
    int* d_tEpiColLoc,
    fp* d_endoT,
    fp* d_epiT,
    fp* d_in2_all,
    fp* d_conv_all,
    fp* d_in2_pad_cumv_all,
    fp* d_in2_pad_cumv_sel_all,
    fp* d_in2_sub_cumh_all,
    fp* d_in2_sub_cumh_sel_all,
    fp* d_in2_sub2_all,
    fp* d_in2_sqr_all,
    fp* d_in2_sqr_sub2_all,
    fp* d_in_sqr_all,
    fp* d_tMask_all,
    fp* d_mask_conv_all,
    fp* d_in_mod_temp_all,
    fp* in_partial_sum_all,
    fp* in_sqr_partial_sum_all,
    fp* par_max_val_all,
    int* par_max_coo_all,
    fp* in_final_sum_all,
    fp* in_sqr_final_sum_all,
    fp* denomT_all,
    fp* checksum)
{
    int bx_max = d_common.endoPoints + d_common.epiPoints;
#pragma omp parallel
    {
        int tx = omp_get_thread_num();
        int num_threads = omp_get_num_threads();

#pragma omp for schedule(static)
        for (int bx = 0; bx < bx_max; bx++) {
            int d_unique_point_no;
            int* d_unique_d_Row;
            int* d_unique_d_Col;
            int* d_unique_d_tRowLoc;
            int* d_unique_d_tColLoc;
            fp* d_in;

            if (bx < d_common.endoPoints) {
                d_unique_point_no = bx;
                d_unique_d_Row = d_endoRow;
                d_unique_d_Col = d_endoCol;
                d_unique_d_tRowLoc = d_tEndoRowLoc;
                d_unique_d_tColLoc = d_tEndoColLoc;
                d_in = &d_endoT[d_unique_point_no * d_common.in_elem];
            } else {
                d_unique_point_no = bx - d_common.endoPoints;
                d_unique_d_Row = d_epiRow;
                d_unique_d_Col = d_epiCol;
                d_unique_d_tRowLoc = d_tEpiRowLoc;
                d_unique_d_tColLoc = d_tEpiColLoc;
                d_in = &d_epiT[d_unique_point_no * d_common.in_elem];
            }

            fp* d_unique_d_in2 = &d_in2_all[bx * d_common.in2_elem];
            fp* d_unique_d_conv = &d_conv_all[bx * d_common.conv_elem];
            fp* d_unique_d_in2_pad_cumv = &d_in2_pad_cumv_all[bx * d_common.in2_pad_cumv_elem];
            fp* d_unique_d_in2_pad_cumv_sel = &d_in2_pad_cumv_sel_all[bx * d_common.in2_pad_cumv_sel_elem];
            fp* d_unique_d_in2_sub_cumh = &d_in2_sub_cumh_all[bx * d_common.in2_sub_cumh_elem];
            fp* d_unique_d_in2_sub_cumh_sel = &d_in2_sub_cumh_sel_all[bx * d_common.in2_sub_cumh_sel_elem];
            fp* d_unique_d_in2_sub2 = &d_in2_sub2_all[bx * d_common.in2_sub2_elem];
            fp* d_unique_d_in2_sqr = &d_in2_sqr_all[bx * d_common.in2_sqr_elem];
            fp* d_unique_d_in2_sqr_sub2 = &d_in2_sqr_sub2_all[bx * d_common.in2_sqr_sub2_elem];
            fp* d_unique_d_in_sqr = &d_in_sqr_all[bx * d_common.in_sqr_elem];
            fp* d_unique_d_tMask = &d_tMask_all[bx * d_common.tMask_elem];
            fp* d_unique_d_mask_conv = &d_mask_conv_all[bx * d_common.mask_conv_elem];

            fp* d_in_mod_temp = &d_in_mod_temp_all[bx * d_common.in_elem];
            fp* in_partial_sum = &in_partial_sum_all[bx * d_common.in_cols];
            fp* in_sqr_partial_sum = &in_sqr_partial_sum_all[bx * d_common.in_sqr_rows];
            fp* par_max_val = &par_max_val_all[bx * d_common.mask_conv_rows];
            int* par_max_coo = &par_max_coo_all[bx * d_common.mask_conv_rows];

            fp* in_final_sum = &in_final_sum_all[bx];
            fp* in_sqr_final_sum = &in_sqr_final_sum_all[bx];
            fp* denomT = &denomT_all[bx];

#ifdef TEST_CHECKSUM
            if (bx == 0 && tx == 0) {
                for (int i = 0; i < CHECK; i++) {
                    checksum[i] = 0;
                }
            }
#endif

            if (d_frame_no == 0) {
#ifdef INIT
                if (tx == 0) {
                    for (int i = 0; i < d_common.no_frames; i++) {
                        d_unique_d_tRowLoc[d_unique_point_no * d_common.no_frames + i] = 0;
                        d_unique_d_tColLoc[d_unique_point_no * d_common.no_frames + i] = 0;
                    }
                    for (int i = 0; i < d_common.in_elem; i++) {
                        d_in[i] = 0;
                    }
                }
#endif
                // No barrier inside for-loop, so we use a critical section to synchronize
#pragma omp barrier

                if (tx == 0) {
                    int pointer = d_unique_point_no * d_common.no_frames + d_frame_no;
                    d_unique_d_tRowLoc[pointer] = d_unique_d_Row[d_unique_point_no];
                    d_unique_d_tColLoc[pointer] = d_unique_d_Col[d_unique_point_no];
                }

                for (int ei_new = tx; ei_new < d_common.in_elem; ei_new += num_threads) {
                    int row = (ei_new + 1) % d_common.in_rows - 1;
                    int col = (ei_new + 1) / d_common.in_rows;
                    if ((ei_new + 1) % d_common.in_rows == 0) {
                        row = d_common.in_rows - 1;
                        col = col - 1;
                    }
                    col = col - 1;

                    int ori_row = d_unique_d_Row[d_unique_point_no] - 25 + row - 1;
                    int ori_col = d_unique_d_Col[d_unique_point_no] - 25 + col - 1;
                    int ori_pointer = ori_col * d_common.frame_rows + ori_row;

                    d_in[col * d_common.in_rows + row] = d_frame[ori_pointer];
                }
#pragma omp barrier

#ifdef TEST_CHECKSUM
                if (bx == 0 && tx == 0) {
                    for (int i = 0; i < d_common.in_elem; i++) {
                        checksum[0] = checksum[0] + d_in[i];
                    }
                }
#pragma omp barrier
#endif
            }

            if (d_frame_no != 0) {
#ifdef INIT
                if (tx == 0) {
                    for (int i = 0; i < d_common.in2_elem; i++) d_unique_d_in2[i] = 0;
                    for (int i = 0; i < d_common.conv_elem; i++) d_unique_d_conv[i] = 0;
                    for (int i = 0; i < d_common.in2_pad_cumv_elem; i++) d_unique_d_in2_pad_cumv[i] = 0;
                    for (int i = 0; i < d_common.in2_pad_cumv_sel_elem; i++) d_unique_d_in2_pad_cumv_sel[i] = 0;
                    for (int i = 0; i < d_common.in2_sub_cumh_elem; i++) d_unique_d_in2_sub_cumh[i] = 0;
                    for (int i = 0; i < d_common.in2_sub_cumh_sel_elem; i++) d_unique_d_in2_sub_cumh_sel[i] = 0;
                    for (int i = 0; i < d_common.in2_sub2_elem; i++) d_unique_d_in2_sub2[i] = 0;
                    for (int i = 0; i < d_common.in2_sqr_elem; i++) d_unique_d_in2_sqr[i] = 0;
                    for (int i = 0; i < d_common.in2_sqr_sub2_elem; i++) d_unique_d_in2_sqr_sub2[i] = 0;
                    for (int i = 0; i < d_common.in_sqr_elem; i++) d_unique_d_in_sqr[i] = 0;
                    for (int i = 0; i < d_common.tMask_elem; i++) d_unique_d_tMask[i] = 0;
                    for (int i = 0; i < d_common.mask_conv_elem; i++) d_unique_d_mask_conv[i] = 0;

                    for (int i = 0; i < d_common.in_elem; i++) d_in_mod_temp[i] = 0;
                    for (int i = 0; i < d_common.in_cols; i++) in_partial_sum[i] = 0;
                    for (int i = 0; i < d_common.in_sqr_rows; i++) in_sqr_partial_sum[i] = 0;
                    for (int i = 0; i < d_common.mask_conv_rows; i++) par_max_val[i] = 0;
                    for (int i = 0; i < d_common.mask_conv_rows; i++) par_max_coo[i] = 0;

                    in_final_sum[0] = 0;
                    in_sqr_final_sum[0] = 0;
                    denomT[0] = 0;
                }
#endif
#pragma omp barrier

                int in2_rowlow = d_unique_d_Row[d_unique_point_no] - d_common.sSize;
                int in2_collow = d_unique_d_Col[d_unique_point_no] - d_common.sSize;

                for (int ei_new = tx; ei_new < d_common.in2_elem; ei_new += num_threads) {
                    int row = (ei_new + 1) % d_common.in2_rows - 1;
                    int col = (ei_new + 1) / d_common.in2_rows;
                    if ((ei_new + 1) % d_common.in2_rows == 0) {
                        row = d_common.in2_rows - 1;
                        col = col - 1;
                    }
                    col = col - 1;

                    int ori_row = row + in2_rowlow - 1;
                    int ori_col = col + in2_collow - 1;
                    d_unique_d_in2[ei_new] = d_frame[ori_col * d_common.frame_rows + ori_row];
                }
#pragma omp barrier

#ifdef TEST_CHECKSUM
                if (bx == 0 && tx == 0) {
                    for (int i = 0; i < d_common.in2_elem; i++) {
                        checksum[1] = checksum[1] + d_unique_d_in2[i];
                    }
                }
#pragma omp barrier
#endif

                for (int ei_new = tx; ei_new < d_common.in_elem; ei_new += num_threads) {
                    int row = (ei_new + 1) % d_common.in_rows - 1;
                    int col = (ei_new + 1) / d_common.in_rows;
                    if ((ei_new + 1) % d_common.in_rows == 0) {
                        row = d_common.in_rows - 1;
                        col = col - 1;
                    }
                    col = col - 1;

                    int rot_row = (d_common.in_rows - 1) - row;
                    int rot_col = (d_common.in_rows - 1) - col;
                    d_in_mod_temp[ei_new] = d_in[rot_col * d_common.in_rows + rot_row];
                }
#pragma omp barrier

#ifdef TEST_CHECKSUM
                if (bx == 0 && tx == 0) {
                    for (int i = 0; i < d_common.in_elem; i++) {
                        checksum[2] = checksum[2] + d_in_mod_temp[i];
                    }
                }
#pragma omp barrier
#endif

                for (int ei_new = tx; ei_new < d_common.conv_elem; ei_new += num_threads) {
                    int ic = (ei_new + 1) % d_common.conv_rows;
                    int jc = (ei_new + 1) / d_common.conv_rows;
                    if ((ei_new + 1) % d_common.conv_rows == 0) {
                        ic = d_common.conv_rows;
                        jc = jc - 1;
                    }

                    int j = jc + d_common.joffset;
                    int jp1 = j + 1;
                    int ja1 = (d_common.in2_cols < jp1) ? (jp1 - d_common.in2_cols) : 1;
                    int ja2 = (d_common.in_cols < j) ? d_common.in_cols : j;

                    int i = ic + d_common.ioffset;
                    int ip1 = i + 1;
                    int ia1 = (d_common.in2_rows < ip1) ? (ip1 - d_common.in2_rows) : 1;
                    int ia2 = (d_common.in_rows < i) ? d_common.in_rows : i;

                    fp s = 0;
                    for (int ja = ja1; ja <= ja2; ja++) {
                        int jb = jp1 - ja;
                        for (int ia = ia1; ia <= ia2; ia++) {
                            int ib = ip1 - ia;
                            s += d_in_mod_temp[d_common.in_rows * (ja - 1) + ia - 1] * d_unique_d_in2[d_common.in2_rows * (jb - 1) + ib - 1];
                        }
                    }
                    d_unique_d_conv[ei_new] = s;
                }
#pragma omp barrier

#ifdef TEST_CHECKSUM
                if (bx == 0 && tx == 0) {
                    for (int i = 0; i < d_common.conv_elem; i++) {
                        checksum[3] = checksum[3] + d_unique_d_conv[i];
                    }
                }
#pragma omp barrier
#endif

                for (int ei_new = tx; ei_new < d_common.in2_pad_cumv_elem; ei_new += num_threads) {
                    int row = (ei_new + 1) % d_common.in2_pad_cumv_rows - 1;
                    int col = (ei_new + 1) / d_common.in2_pad_cumv_rows;
                    if ((ei_new + 1) % d_common.in2_pad_cumv_rows == 0) {
                        row = d_common.in2_pad_cumv_rows - 1;
                        col = col - 1;
                    }
                    col = col - 1;

                    if (row > (d_common.in2_pad_add_rows - 1) &&
